import React from "react";
import classes from './Post.module.css';

const Post = (props) => {
    return <div className={classes.item}>
        <div className={classes.posts}>
            <div>
            <img className={classes.itemimg} src='https://avatarko.ru/img/kartinka/24/zhivotnye_kot_computer_23354.jpg' alt='Аватар'/>



            </div>
        <div className={classes.posttext}>
            {props.post}
        </div>
            <div className={classes.postlike}>
                {props.likesCount} like

            </div>
            <img className={classes.itemimg} src={props.photo} alt='Аватар'/>
        </div>
       </div>

}

export default Post;
